"use client";
import { signIn } from "next-auth/react";
import { useState } from "react";
import { useRouter } from "next/navigation";
import Link from "next/link";

export default function LoginPage() {
    // 1. Ganti 'username' menjadi 'identifier' agar sinkron dengan input
    const [identifier, setIdentifier] = useState(""); 
    const [password, setPassword] = useState("");
    const router = useRouter();

    const handleLogin = async (e: React.FormEvent) => {
        e.preventDefault();
        
        // 2. Kirim 'identifier' ke NextAuth
        const res = await signIn("credentials", {
        identifier, // Ini harus 'identifier' agar cocok dengan route.ts
        password,
        redirect: false,
        });

        if (res?.ok) {
        router.push("/dashboard");
        router.refresh();
        } else {
        alert("Login Gagal! Cek kembali username/email dan password kamu.");
        }
    };

    return (
        <div className="min-h-screen flex items-center justify-center bg-[#0f172a]">
        <div className="bg-white p-8 rounded-2xl shadow-2xl w-full max-w-sm">
            <h1 className="text-2xl font-bold mb-6 text-slate-800 text-center">Login ET-Pareto</h1>
            
            <form onSubmit={handleLogin} className="space-y-4">
            <input
                type="text"
                placeholder="Username atau Email"
                className="w-full p-3 border border-slate-200 rounded-lg text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-500"
                // 3. Pastikan memanggil setIdentifier
                onChange={(e) => setIdentifier(e.target.value)} 
                required
            />
            <input
                type="password"
                placeholder="Password"
                className="w-full p-3 border border-slate-200 rounded-lg text-slate-800 focus:outline-none focus:ring-2 focus:ring-blue-500"
                onChange={(e) => setPassword(e.target.value)}
                required
            />
            <button className="w-full bg-blue-600 text-white p-3 rounded-lg font-bold hover:bg-blue-700 transition duration-200">
                Sign In
            </button>
            </form>

            <div className="mt-6">
            <div className="relative flex py-2 items-center">
                <div className="flex-grow border-t border-slate-200"></div>
                <span className="flex-shrink mx-4 text-slate-400 text-xs uppercase text-center">Atau</span>
                <div className="flex-grow border-t border-slate-200"></div>
            </div>
            
            <button
                type="button" 
                onClick={() => signIn("google", { callbackUrl: "/dashboard" })}
                className="w-full mt-4 flex items-center justify-center gap-3 border border-slate-300 p-3 rounded-lg hover:bg-slate-50 transition text-slate-700 font-medium text-sm"
            >
                <img src="https://authjs.dev/img/providers/google.svg" width="18" alt="Google logo" />
                Sign in with Google
            </button>
            </div>

            <div className="mt-8 text-center space-y-2">
            <p className="text-sm text-slate-500 text-center">
                Belum punya akun? {" "}
                <Link href="/register" className="text-blue-600 font-bold hover:underline">
                Daftar di sini
                </Link>
            </p>
            <div className="text-center">
                <Link href="/forgot-password" className="text-slate-400 hover:text-slate-600 text-xs italic">
                Lupa Password?
                </Link>
            </div>
            </div>
        </div>
        </div>
    );
}